import { Shield, Brain, Globe, Network, Code2, Database } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { glass } from '../utils/glass';

export default function About() {
  const { dark, lang } = useApp();
  const tr = t[lang];

  const bg     = dark ? '#13131e' : '#f5f0e8';
  const tBase  = dark ? '#f0f0f8' : '#1a1a2e';
  const tMuted = dark ? 'rgba(255,255,255,0.6)' : '#5a5a72';
  const tStrong = dark ? '#ffffff' : '#1a1a2e';

  const skills = [
    { Icon: Shield,   key: 'cyber' },
    { Icon: Brain,    key: 'ai' },
    { Icon: Network,  key: 'net' },
    { Icon: Globe,    key: 'web' },
    { Icon: Code2,    key: 'code' },
    { Icon: Database, key: 'db' },
  ];

  return (
    <section id="about" style={{ background: bg }} className="py-24 px-[5%] transition-colors duration-300">
      <SectionHeader tag={tr.aboutTag} title={tr.aboutTitle} />
      <div className="grid md:grid-cols-2 gap-16 items-start">

        {/* Text */}
        <div className="reveal space-y-5">
          <p className="text-[1.05rem] leading-[1.95]" style={{ color: tMuted }}>
            {tr.aboutP1.split('Kareem Basem').map((part, i) =>
              i === 0 ? part : <span key={i}><strong style={{ color: tStrong }}>Kareem Basem</strong>{part}</span>
            )}
          </p>
          <p className="text-[0.95rem] leading-[1.85]" style={{ color: tMuted }}>{tr.aboutP2}</p>

          {/* Scout badges */}
          <div className="space-y-2 pt-1">
            <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-xs font-semibold text-amber2"
              style={{ background: 'rgba(240,165,0,0.10)', border: '1px solid rgba(240,165,0,0.22)' }}>
              🏅 {lang === 'ar' ? 'بطل الكشافة الوطني — المركز الأول (2020)' : 'National Scout Excellence Champion — 1st Place (2020)'}
            </div>
            <br />
            <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-xs font-semibold text-amber2"
              style={{ background: 'rgba(240,165,0,0.07)', border: '1px solid rgba(240,165,0,0.18)' }}>
              🏆 {lang === 'ar' ? 'مديرية أسيوط — المركز الأول (2019)' : '2019 · Asyut Directorate — Scout Excellence, 1st Place'}
            </div>
          </div>
        </div>

        {/* Skills grid */}
        <div className="reveal delay-2 grid grid-cols-2 gap-3">
          {skills.map(({ Icon, key }) => (
            <div key={key}
              className="flex items-center gap-3 px-4 py-3.5 rounded-xl transition-all duration-200 hover:-translate-x-[-5px] cursor-default"
              style={{
                ...glass(dark),
                transition: 'all 0.25s',
              }}
              onMouseEnter={e => {
                e.currentTarget.style.transform = 'translateX(5px)';
                e.currentTarget.style.boxShadow = '0 8px 28px rgba(240,165,0,0.15)';
                e.currentTarget.style.borderColor = 'rgba(240,165,0,0.3)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = 'translateX(0)';
                e.currentTarget.style.boxShadow = dark ? '0 4px 24px rgba(0,0,0,0.3)' : '0 4px 24px rgba(26,26,46,0.08)';
                e.currentTarget.style.borderColor = dark ? 'rgba(255,255,255,0.10)' : 'rgba(255,255,255,0.80)';
              }}>
              <span className="text-amber flex-shrink-0"><Icon size={18} /></span>
              <span className="text-sm font-medium" style={{ color: tBase }}>{tr.skills[key]}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
